starter:
def window_sums(a, k):
    # your code here
    pass

solution:
def window_sums(a, k):
    out = []
    for i in range(len(a) - k + 1):
        total = 0
        for j in range(i, i + k):
            total += a[j]
        out.append(total)
    return out
